var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"평화로운 유원지군요. 동물원이 들어섰다더니 구경거리도 아주 많네요.","JPN":"穏やかな雰囲気の遊園地ですね。動物園ができたと聞いたのですが、見どころも満載です。","ENG":"It’s a peaceful amusement park. There being a zoo, I believe there’re lots to see.","TWN":"真是悠閒的遊樂園，動物園蓋起來後，有很多可以逛的呢。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"즐거워 보이는구나.","JPN":"楽しそうじゃな。","ENG":"You look happy.","TWN":"感覺好好玩喔。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 여긴 깜찍한 볼거리가 있습니다, 주인님.","JPN":"フフ、ここではかわいいものを見物できますよ。ご主人様。","ENG":"Ha ha, look at the cute animals here, Mistress.","TWN":"呵呵，主人您看，這個好可愛。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이것 보십시오. 바닥에 느긋하게 달라붙어서 이빨을 드러낸 모습이 사랑스럽지 않습니까?","JPN":"見てください。のんびりと地面に寝転んで歯を剥きだした姿、愛おしくありませんか？","ENG":"Look here. Lying on the floor showing its teeth... Doesn’t it look lovely?","TWN":"您看牠趴在地上露出牙齒的模樣，是不是很可愛？"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"흐음, 그러냐?","JPN":"ふむ、そうか？","ENG":"Hmm, does it?","TWN":"嗯哼，是嗎？"},"stage":{"bg":"PARK","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"네가 악어를 좋아하는 건 처음 알았구나.","JPN":"其方がワニ好きだとは、初めて知ったぞ。","ENG":"I didn’t know you had a liking for crocodiles.","TWN":"原來你喜歡鱷魚喔。"},"stage":{"bg":"PARK","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그러게.","JPN":"そうだな。","ENG":"I didn’t know either.","TWN":"是喔？"},"stage":{"bg":"PARK","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"까짓 거, 돈 받으면 저것도 몇 마리 사지 뭐.","JPN":"そんなに金をもらえるんなら、あれも何匹か買おうじゃないか。","ENG":"I guess I’ll get a few crocodiles once I get the money.","TWN":"小意思，等我賺到錢之後買幾隻送哥哥！"},"stage":{"bg":"PARK","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"잠깐만요, 감독님.","JPN":"待ってください、監督。","ENG":"Wait.","TWN":"我說導演，"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"왜 유원지죠? 제가 받은 대본에는 이런 장소가 없었는데요?","JPN":"なんで遊園地なんですか？　私がもらった台本にこんな場所はなかったはずですけど。","ENG":"Why are we at an amusement park? There wasn’t a place like this in the script.","TWN":"為什麼要來遊樂園？我拿到的劇本裡完全沒有提到遊樂園啊？"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그야 리허설에 없던 내용이기 때문이지.","JPN":"そりゃそうだ、リハーサルにはなかった内容だからな。","ENG":"It’s because this isn’t part of the rehearsal.","TWN":"因為這不在排演的內容裡。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그리고 이번 촬영분은 다음 시즌의 예고편으로 사용될 거야.","JPN":"そして今回の撮影は次のシーズンの予告編として使われる。","ENG":"What we’re filming here will be used as a trailer for the next season.","TWN":"而且今天拍攝的內容，會直接拿來當作預告片。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"네? 그렇다는 건 이번 씬이…?","JPN":"えっ？　それはつまりこのシーンが……？","ENG":"What? That means this scene is...?","TWN":"什麼？意思就是…？"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"리허설이 아닌 진짜 촬영이라는 뜻이군요.","JPN":"リハーサルではなく、本番ということですね。","ENG":"Not part of the rehearsal, but a real shoot.","TWN":"今天不是排演，是正式拍攝。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"예정엔 없었지만 예술이란 원래 뜻밖의 상황에서 탄생하는 법이니까.","JPN":"予定にはなかったけど、芸術とは意外な状況から誕生するものだからな。","ENG":"It wasn’t planned, but as you know, art is created in the spur of the moment!","TWN":"雖然不在計畫之內，不過藝術本來就是在出其不意的情況下產生的。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"좋아요. 자연스러운 로맨스 연기 실력을 보겠다는 거죠?","JPN":"わかりました。自然なロマンス演技の実力を見るってことですよね？","ENG":"All right. So you’re looking for natural romance acting skills, right?","TWN":"好吧，意思就是要自然地展現浪漫的演技是吧？"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"차라리 잘 됐네요. 순수한 연기라면 내가 저 여자한테 질 리는 없을 테니까.","JPN":"むしろよかったです。演技力なら、私があの女に負けるわけないですから。","ENG":"Maybe it’s better this way. I won’t lose to that girl when it comes to pure acting skills.","TWN":"那正好！單純比演技的話，我可不會輸她！"},"stage":{"bg":"PARK","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"까불지 마라. 뭉개버린다.","JPN":"調子に乗るな。ぶっ潰すぞ。","ENG":"Don’t tread on me or I’ll smush you.","TWN":"少囂張，我可不會手下留情！"},"stage":{"bg":"PARK","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"그런다고 누가 쫄 것 같아? 법정 가고 싶으면 쳐보시던가.","JPN":"そんなこと言われたって怖くないわ。訴えられたいなら、殴ってみなさいよ。","ENG":"You think I’ll freak out? Hit me if you can. We’ll meet at court.","TWN":"你以為這樣我就會怕嗎？敢打我試試看，我會告到你上法院！"},"stage":{"bg":"PARK","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"아서라, 의뢰인. 저 시종 녀석은 농담을 할 줄 모른단다.","JPN":"よせ、依頼人。あの僕は冗談が通じぬ。","ENG":"Stop it, you. My servant doesn’t know how to make jokes.","TWN":"委託人，勸你少說兩句，我的僕人會當真的。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"…흥, 저런 깡패가 무슨 연기를 하겠다고.","JPN":"……フン、あんなチンピラが演技だなんて。","ENG":"...Hmpf, that gangster will never be good at acting.","TWN":"…哼，那個女流氓懂什麼演戲！"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};